#include "XSbench_header.h"

#ifdef OPENMP
#include <omp.h>
#endif

unsigned long long run_event_based_simulation(Inputs in, SimulationData SD, int mype)
{
	if( mype == 0) printf("Running baseline event-based simulation...\n");

	unsigned long long verification_scalar = 0;

	#ifdef OPENMP
	#pragma omp parallel for reduction(+:verification_scalar)
	#endif
	for( int i = 0; i < in.lookups; i++ )
	{
		uint64_t seed = STARTING_SEED;
		seed = fast_forward_LCG(seed, 2*i);
		double p_energy = LCG_random_double(&seed);
		int mat = pick_mat(&seed);

		double macro_xs_vector[5] = {0};
		calculate_macro_xs(
			p_energy, mat, in.n_isotopes, in.n_gridpoints,
			SD.num_nucs, SD.concs, SD.unionized_energy_array,
			SD.index_grid, SD.nuclide_grid, SD.mats,
			macro_xs_vector, in.grid_type, in.hash_bins, SD.max_num_nucs);

		double max = -1.0;
		int max_idx = 0;
		for(int j = 0; j < 5; j++ )
		{
			if( macro_xs_vector[j] > max )
			{
				max = macro_xs_vector[j];
				max_idx = j;
			}
		}
		verification_scalar += (max_idx+1);
	}

	if( mype == 0) printf("Reducing verification results...\n");

	return verification_scalar;
}

void calculate_micro_xs( double p_energy, int nuc, long n_isotopes,
	long n_gridpoints, double * egrid, int * index_data,
	NuclideGridPoint * nuclide_grids, long idx, double * xs_vector,
	int grid_type, int hash_bins )
{
	double f;
	NuclideGridPoint * low, * high;

	if( grid_type == NUCLIDE )
	{
		idx = grid_search_nuclide( n_gridpoints, p_energy, &nuclide_grids[nuc*n_gridpoints], 0, n_gridpoints-1);
		if( idx == n_gridpoints - 1 )
			low = &nuclide_grids[nuc*n_gridpoints + idx - 1];
		else
			low = &nuclide_grids[nuc*n_gridpoints + idx];
	}
	else if( grid_type == UNIONIZED) 
	{
		if( index_data[idx * n_isotopes + nuc] == n_gridpoints - 1 )
			low = &nuclide_grids[nuc*n_gridpoints + index_data[idx * n_isotopes + nuc] - 1];
		else
			low = &nuclide_grids[nuc*n_gridpoints + index_data[idx * n_isotopes + nuc]];
	}
	else 
	{
		int u_low = index_data[idx * n_isotopes + nuc];
		int u_high;
		if( idx == hash_bins - 1 )
			u_high = n_gridpoints - 1;
		else
			u_high = index_data[(idx+1)*n_isotopes + nuc] + 1;

		double e_low  = nuclide_grids[nuc*n_gridpoints + u_low].energy;
		double e_high = nuclide_grids[nuc*n_gridpoints + u_high].energy;
		int lower;
		if( p_energy <= e_low )
			lower = 0;
		else if( p_energy >= e_high )
			lower = n_gridpoints - 1;
		else
			lower = grid_search_nuclide( n_gridpoints, p_energy, &nuclide_grids[nuc*n_gridpoints], u_low, u_high);

		if( lower == n_gridpoints - 1 )
			low = &nuclide_grids[nuc*n_gridpoints + lower - 1];
		else
			low = &nuclide_grids[nuc*n_gridpoints + lower];
	}

	high = low + 1;
	f = (high->energy - p_energy) / (high->energy - low->energy);

	xs_vector[0] = high->total_xs - f * (high->total_xs - low->total_xs);
	xs_vector[1] = high->elastic_xs - f * (high->elastic_xs - low->elastic_xs);
	xs_vector[2] = high->absorbtion_xs - f * (high->absorbtion_xs - low->absorbtion_xs);
	xs_vector[3] = high->fission_xs - f * (high->fission_xs - low->fission_xs);
	xs_vector[4] = high->nu_fission_xs - f * (high->nu_fission_xs - low->nu_fission_xs);
}

void calculate_macro_xs( double p_energy, int mat, long n_isotopes,
	long n_gridpoints, int * num_nucs, double * concs,
	double * egrid, int * index_data, NuclideGridPoint * nuclide_grids,
	int * mats, double * macro_xs_vector, int grid_type, int hash_bins, int max_num_nucs )
{
	int p_nuc; 
	long idx = -1;	
	double conc; 

	for( int k = 0; k < 5; k++ )
		macro_xs_vector[k] = 0;

	if( grid_type == UNIONIZED )
		idx = grid_search( n_isotopes * n_gridpoints, p_energy, egrid);	
	else if( grid_type == HASH )
	{
		double du = 1.0 / hash_bins;
		idx = p_energy / du;
	}

	for( int j = 0; j < num_nucs[mat]; j++ )
	{
		double xs_vector[5];
		p_nuc = mats[mat*max_num_nucs + j];
		conc = concs[mat*max_num_nucs + j];
		calculate_micro_xs( p_energy, p_nuc, n_isotopes, n_gridpoints,
		                    egrid, index_data, nuclide_grids, idx, xs_vector, grid_type, hash_bins );
		for( int k = 0; k < 5; k++ )
			macro_xs_vector[k] += xs_vector[k] * conc;
	}
}

long grid_search( long n, double quarry, double * A)
{
	long lowerLimit = 0;
	long upperLimit = n-1;
	long examinationPoint;
	long length = upperLimit - lowerLimit;

	while( length > 1 )
	{
		examinationPoint = lowerLimit + ( length / 2 );
		if( A[examinationPoint] > quarry )
			upperLimit = examinationPoint;
		else
			lowerLimit = examinationPoint;
		length = upperLimit - lowerLimit;
	}

	return lowerLimit;
}

long grid_search_nuclide( long n, double quarry, NuclideGridPoint * A, long low, long high)
{
	long lowerLimit = low;
	long upperLimit = high;
	long examinationPoint;
	long length = upperLimit - lowerLimit;

	while( length > 1 )
	{
		examinationPoint = lowerLimit + ( length / 2 );
		if( A[examinationPoint].energy > quarry )
			upperLimit = examinationPoint;
		else
			lowerLimit = examinationPoint;
		length = upperLimit - lowerLimit;
	}

	return lowerLimit;
}

int pick_mat( uint64_t * seed )
{
	double dist[12];
	dist[0]  = 0.140;	
	dist[1]  = 0.052;	
	dist[2]  = 0.275;	
	dist[3]  = 0.134;	
	dist[4]  = 0.154;	
	dist[5]  = 0.064;	
	dist[6]  = 0.066;	
	dist[7]  = 0.055;	
	dist[8]  = 0.008;	
	dist[9]  = 0.015;	
	dist[10] = 0.025;	
	dist[11] = 0.013;	

	double roll = LCG_random_double(seed);

	for( int i = 0; i < 12; i++ )
	{
		double running = 0;
		for( int j = i; j > 0; j-- )
			running += dist[j];
		if( roll < running )
			return i;
	}

	return 0;
}

double LCG_random_double(uint64_t * seed)
{
	const uint64_t m = 9223372036854775808ULL; 
	const uint64_t a = 2806196910506780709ULL;
	const uint64_t c = 1ULL;
	*seed = (a * (*seed) + c) % m;
	return (double) (*seed) / (double) m;
}	

uint64_t fast_forward_LCG(uint64_t seed, uint64_t n)
{
	const uint64_t m = 9223372036854775808ULL; 
	uint64_t a = 2806196910506780709ULL;
	uint64_t c = 1ULL;

	n = n % m;

	uint64_t a_new = 1;
	uint64_t c_new = 0;

	while(n > 0) 
	{
		if(n & 1)
		{
			a_new *= a;
			c_new = c_new * a + c;
		}
		c *= (a + 1);
		a *= a;

		n >>= 1;
	}

	return (a_new * seed + c_new) % m;
}

unsigned long long run_event_based_simulation_optimization_1(Inputs in, SimulationData SD, int mype)
{
	const char * optimization_name = "Optimization 1 - basic sample/lookup kernel splitting";

	if( mype == 0) printf("Simulation Kernel:\"%s\"\n", optimization_name);

	if( mype == 0) printf("Allocating additional data required by kernel...\n");
	size_t sz;
	size_t total_sz = 0;

	sz = in.lookups * sizeof(double);
	SD.p_energy_samples = (double *) malloc(sz);
	total_sz += sz;
	SD.length_p_energy_samples = in.lookups;

	sz = in.lookups * sizeof(int);
	SD.mat_samples = (int *) malloc(sz);
	total_sz += sz;
	SD.length_mat_samples = in.lookups;

	if( mype == 0) printf("Allocated an additional %.0lf MB of data.\n", total_sz/1024.0/1024.0);

	if( mype == 0) printf("Beginning optimized simulation...\n");

	#ifdef OPENMP
	#pragma omp parallel for
	#endif
	for( int i = 0; i < in.lookups; i++ )
	{
		uint64_t seed = STARTING_SEED;
		seed = fast_forward_LCG(seed, 2*i);
		double p_energy = LCG_random_double(&seed);
		int mat = pick_mat(&seed);
		SD.p_energy_samples[i] = p_energy;
		SD.mat_samples[i] = mat;
	}

	unsigned long long verification_scalar = 0;

	#ifdef OPENMP
	#pragma omp parallel for reduction(+:verification_scalar)
	#endif
	for( int i = 0; i < in.lookups; i++ )
	{
		double macro_xs_vector[5] = {0};
		calculate_macro_xs(
			SD.p_energy_samples[i], SD.mat_samples[i],
			in.n_isotopes, in.n_gridpoints, SD.num_nucs, SD.concs,
			SD.unionized_energy_array, SD.index_grid, SD.nuclide_grid,
			SD.mats, macro_xs_vector, in.grid_type, in.hash_bins, SD.max_num_nucs);

		double max = -1.0;
		int max_idx = 0;
		for(int j = 0; j < 5; j++ )
		{
			if( macro_xs_vector[j] > max )
			{
				max = macro_xs_vector[j];
				max_idx = j;
			}
		}
		verification_scalar += (max_idx+1);
	}

	if( mype == 0) printf("Reducing verification results...\n");

	return verification_scalar;
}

SimulationData move_simulation_data_to_device( Inputs in, int mype, SimulationData SD )
{
	if(mype == 0) printf("Allocating simulation data...\n");

	size_t sz;
	size_t total_sz = 0;

	SimulationData GSD = SD;

	sz = GSD.length_num_nucs * sizeof(int);
	GSD.num_nucs = (int *) malloc(sz);
	memcpy(GSD.num_nucs, SD.num_nucs, sz);
	total_sz += sz;

	sz = GSD.length_concs * sizeof(double);
	GSD.concs = (double *) malloc(sz);
	memcpy(GSD.concs, SD.concs, sz);
	total_sz += sz;

	sz = GSD.length_mats * sizeof(int);
	GSD.mats = (int *) malloc(sz);
	memcpy(GSD.mats, SD.mats, sz);
	total_sz += sz;

	sz = GSD.length_unionized_energy_array * sizeof(double);
	GSD.unionized_energy_array = (double *) malloc(sz);
	memcpy(GSD.unionized_energy_array, SD.unionized_energy_array, sz);
	total_sz += sz;

	sz = GSD.length_index_grid * sizeof(int);
	GSD.index_grid = (int *) malloc(sz);
	memcpy(GSD.index_grid, SD.index_grid, sz);
	total_sz += sz;

	sz = GSD.length_nuclide_grid * sizeof(NuclideGridPoint);
	GSD.nuclide_grid = (NuclideGridPoint *) malloc(sz);
	memcpy(GSD.nuclide_grid, SD.nuclide_grid, sz);
	total_sz += sz;

	if(mype == 0 ) printf("Initialization complete. Allocated %.0lf MB of data.\n", total_sz/1024.0/1024.0 );

	return GSD;
}

void release_device_memory(SimulationData GSD) {
	free(GSD.num_nucs);
	free(GSD.concs);
	free(GSD.mats);
	free(GSD.unionized_energy_array);
	free(GSD.nuclide_grid);
	free(GSD.p_energy_samples);
	free(GSD.mat_samples);
}

SimulationData grid_init_do_not_profile( Inputs in, int mype )
{
	SimulationData SD;

	size_t nbytes = 0;
	uint64_t seed = 42;	

	if(mype == 0) printf("Initializing nuclide grids...\n");

	SD.length_nuclide_grid = in.n_isotopes * in.n_gridpoints;
	SD.nuclide_grid = (NuclideGridPoint *) malloc( SD.length_nuclide_grid * sizeof(NuclideGridPoint));
	assert(SD.nuclide_grid != NULL);
	nbytes += SD.length_nuclide_grid * sizeof(NuclideGridPoint);
	for( int i = 0; i < SD.length_nuclide_grid; i++ )
	{
		SD.nuclide_grid[i].energy = LCG_random_double(&seed);
		SD.nuclide_grid[i].total_xs = LCG_random_double(&seed);
		SD.nuclide_grid[i].elastic_xs = LCG_random_double(&seed);
		SD.nuclide_grid[i].absorbtion_xs = LCG_random_double(&seed);
		SD.nuclide_grid[i].fission_xs = LCG_random_double(&seed);
		SD.nuclide_grid[i].nu_fission_xs = LCG_random_double(&seed);
	}

	for( int i = 0; i < in.n_isotopes; i++ )
		qsort( &SD.nuclide_grid[i*in.n_gridpoints], in.n_gridpoints, sizeof(NuclideGridPoint), NGP_compare);

	if( in.grid_type == NUCLIDE )
	{
		SD.length_unionized_energy_array = 0;
		SD.length_index_grid = 0;
	}

	if( in.grid_type == UNIONIZED )
	{
		if(mype == 0) printf("Initializing unionized grid...\n");

		SD.length_unionized_energy_array = in.n_isotopes * in.n_gridpoints;
		SD.unionized_energy_array = (double *) malloc( SD.length_unionized_energy_array * sizeof(double));
		assert(SD.unionized_energy_array != NULL );
		nbytes += SD.length_unionized_energy_array * sizeof(double);

		for( int i = 0; i < SD.length_unionized_energy_array; i++ )
			SD.unionized_energy_array[i] = SD.nuclide_grid[i].energy;

		qsort( SD.unionized_energy_array, SD.length_unionized_energy_array, sizeof(double), double_compare);

		SD.length_index_grid = SD.length_unionized_energy_array * in.n_isotopes;
		SD.index_grid = (int *) malloc( SD.length_index_grid * sizeof(int));
		assert(SD.index_grid != NULL);
		nbytes += SD.length_index_grid * sizeof(int);

		int * idx_low = (int *) calloc( in.n_isotopes, sizeof(int));
		assert(idx_low != NULL );
		double * energy_high = (double *) malloc( in.n_isotopes * sizeof(double));
		assert(energy_high != NULL );

		for( int i = 0; i < in.n_isotopes; i++ )
			energy_high[i] = SD.nuclide_grid[i * in.n_gridpoints + 1].energy;

		for( long e = 0; e < SD.length_unionized_energy_array; e++ )
		{
			double unionized_energy = SD.unionized_energy_array[e];
			for( long i = 0; i < in.n_isotopes; i++ )
			{
				if( unionized_energy < energy_high[i]  )
					SD.index_grid[e * in.n_isotopes + i] = idx_low[i];
				else if( idx_low[i] == in.n_gridpoints - 2 )
					SD.index_grid[e * in.n_isotopes + i] = idx_low[i];
				else
				{
					idx_low[i]++;
					SD.index_grid[e * in.n_isotopes + i] = idx_low[i];
					energy_high[i] = SD.nuclide_grid[i * in.n_gridpoints + idx_low[i] + 1].energy;	
				}
			}
		}

		free(idx_low);
		free(energy_high);
	}

	if( in.grid_type == HASH )
	{
		if(mype == 0) printf("Initializing hash grid...\n");
		SD.length_unionized_energy_array = 0;
		SD.length_index_grid = in.hash_bins * in.n_isotopes;
		SD.index_grid = (int *) malloc( SD.length_index_grid * sizeof(int)); 
		assert(SD.index_grid != NULL);
		nbytes += SD.length_index_grid * sizeof(int);

		double du = 1.0 / in.hash_bins;

		for( long e = 0; e < in.hash_bins; e++ )
		{
			double energy = e * du;
			for( long i = 0; i < in.n_isotopes; i++ )
			{
				SD.index_grid[e * in.n_isotopes + i] = grid_search_nuclide( in.n_gridpoints, energy, SD.nuclide_grid + i * in.n_gridpoints, 0, in.n_gridpoints-1);
			}
		}
	}

	if(mype == 0) printf("Initializing material data...\n");

	SD.num_nucs = load_num_nucs(in.n_isotopes);
	SD.length_num_nucs = 12; 

	SD.mats = load_mats(SD.num_nucs, in.n_isotopes, &SD.max_num_nucs);
	SD.length_mats = SD.length_num_nucs * SD.max_num_nucs;

	SD.concs = load_concs(SD.num_nucs, SD.max_num_nucs);
	SD.length_concs = SD.length_mats;

	if(mype == 0) printf("Initialization complete. Allocated %.0lf MB of data on CPU.\n", nbytes/1024.0/1024.0 );

	return SD;
}
